// src/pages/PrintAgendamentos.jsx
import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';

export default function PrintAgendamentos() {
  const location = useLocation();
  // Recebemos de `ListaAgendamentos` via navigate:
  //   state: { disciplinaId, filtros }
  const { disciplinaId, filtros } = location.state || {};

  const [agendamentos, setAgendamentos] = useState([]);
  const [disciplinaNome, setDisciplinaNome] = useState('');
  // Formata a data que vem em ISO (YYYY-MM-DD) para DD/MM/YYYY
  const dataFormatada = filtros?.data ? convertISOToPTBR(filtros.data) : '';

  useEffect(() => {
    // Se houver um ID de disciplina, buscamos o nome dela
    if (disciplinaId) {
      axios
        .get(`/api/disciplinas/${disciplinaId}`)
        .then(res => {
          setDisciplinaNome(res.data.nome);
        })
        .catch(() => {
          setDisciplinaNome('(Disciplina desconhecida)');
        });
    }

    // Em seguida, buscamos todos os agendamentos dessa disciplina
    axios
      .get(`/api/agendamentos?disciplinaId=${disciplinaId}`)
      .then(res => {
        setAgendamentos(res.data);
      })
      .catch(() => {
        setAgendamentos([]);
      });
  }, [disciplinaId]);

  // Assim que o componente montar, disparar o print
  useEffect(() => {
    const timer = setTimeout(() => window.print(), 200);
    return () => clearTimeout(timer);
  }, []);

  function convertISOToPTBR(isoDate) {
    // Recebe 'YYYY-MM-DD', devolve 'DD/MM/YYYY'
    const [yyyy, mm, dd] = isoDate.split('-');
    return `${dd}/${mm}/${yyyy}`;
  }

  return (
    <div style={{ background: '#fff', padding: '32px' }}>
      {/* ======= TOPO: nome da disciplina e data ======= */}
      <div style={{ marginBottom: '16px' }}>
        <h2
          style={{
            fontSize: '24px',
            fontWeight: 'bold',
            marginBottom: '8px',
          }}
        >
          Lista de Agendamentos
        </h2>
        <div style={{ fontSize: '18px' }}>
          <div>
            <strong>Disciplina:</strong> {disciplinaNome}
          </div>
          <div>
            <strong>Data:</strong> {dataFormatada}
          </div>
        </div>
      </div>

      {/* ======= TABELA DE AGENDAMENTOS ======= */}
      <table
        border="1"
        cellSpacing="0"
        cellPadding="8"
        style={{
          marginTop: '24px',
          width: '100%',
          borderCollapse: 'collapse',
          fontSize: '16px',
        }}
      >
        <thead>
          <tr>
            <th>N°</th>
            <th>Operador</th>
            <th>Auxiliar</th>
            <th>Paciente</th>
            <th>Telefone</th>
            <th>Data</th>
            <th>Hora</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx}>
              <td>{idx + 1}</td>
              <td>{ag.operadorNome || '-'}</td>
              <td>{ag.auxiliarNome || '-'}</td>
              <td>{ag.pacienteNome || '-'}</td>
              <td>{ag.telefone || '-'}</td>
              <td>
                {ag.data
                  ? ag.data.slice(0, 10).split('-').reverse().join('/')
                  : '-'}
              </td>
              <td>{ag.hora || '-'}</td>
              <td>{ag.status || '-'}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Força o fundo branco ao imprimir */}
      <style>
        {`
          @media print {
            body { background: #fff !important; }
          }
        `}
      </style>
    </div>
  );
}
